117		// Browser reader goroutine
118		browserCh := make(chan clientMsg, 16)
119		go func() {
120			defer outerCancel()
121			for {
122				_, data, err := conn.ReadMessage()
123				if err != nil {
124					return
125				}
126				var cm clientMsg
127				if json.Unmarshal(data, &cm) == nil {
128					browserCh <- cm
129				}
130			}
131		}()
132	
133		// switchTo joins a channel, sends init + presence, starts receive loop.
134		var cancelRecv context.CancelFunc
135	
136		switchTo := func(name string) {
137			if cancelRecv != nil {
138				cancelRecv()
139			}
140	
