142			if err != nil {
143				srv.writeJSON(conn, map[string]string{"type": "error", "message": err.Error()})
144				return
145			}
146	
147			history, _ := s.History(name)
148			if history == nil {
149				history = []store.Message{}
150			}
151			srv.writeJSON(conn, initEnv{
152				Type:       "init",
153				SelfID:     srv.selfID,
154				Workspace:  name,
155				History:    history,
156				Workspaces: srv.mgr.List(),
157			})
