159			srv.writeJSON(conn, srv.presenceEnv(name, tracker))
160	
161			recvCtx, cancel := context.WithCancel(outerCtx)
162			cancelRecv = cancel
163			go ws.ReadLoopInto(recvCtx, func(m transport.Message) {
164				if m.MsgType == transport.MsgTypeFile && m.FileData != "" {
165					if raw, decErr := base64.StdEncoding.DecodeString(m.FileData); decErr == nil {
166						_, _ = s.SaveFile(m.FileID, m.FileName, raw)
167					}
168				}
169				select {
170				case incoming <- m:
171				default:
172				}
173			})
174		}
175	
176		switchTo(defaultCh)
177	
178		tick := time.NewTicker(5 * time.Second)
179		defer tick.Stop()
180	
181		for {
182			select {
183			case <-outerCtx.Done():
184				return
185	
186			case cm := <-browserCh:
187				switch cm.Type {
188				case "send":
189					if cm.Body == "" {
190						continue
191					}
192					if ws, s, _, ok := srv.mgr.Get(defaultCh); ok {
193						if err := ws.Publish(outerCtx, cm.Body); err == nil {
194							srv.writeJSON(conn, msgEnv{
195								Type:      "message",
196								Workspace: defaultCh,
197								Message: store.Message{
198									MsgType:   transport.MsgTypeChat,
199									From:      srv.selfID,
200									Workspace: defaultCh,
201									Body:      cm.Body,
202									Timestamp: time.Now().UTC(),
203								},
204							})
205							_ = s
206						}
207					}
208				case "join":
209					if cm.Workspace == "" {
210						continue
211					}
212					defaultCh = cm.Workspace
213					switchTo(cm.Workspace)
214					srv.writeJSON(conn, workspacesEnv{
215						Type:       "workspaces",
216						Workspaces: srv.mgr.List(),
217					})
218				case "list":
219					srv.writeJSON(conn, workspacesEnv{
220						Type:       "workspaces",
221						Workspaces: srv.mgr.List(),
222					})
223				}
224	
225			case m := <-incoming:
226				srv.writeJSON(conn, msgEnv{
227					Type:      "message",
228					Workspace: m.Workspace,
229					Message:   store.Message(m),
230				})
231	
232			case <-tick.C:
233				// Push peer count + online list
234				if _, _, tracker, ok := srv.mgr.Get(defaultCh); ok {
235					srv.writeJSON(conn, srv.presenceEnv(defaultCh, tracker))
236				}
237			}
238		}
239	}
