286		if err != nil || len(data) > maxUploadSize {
287			http.Error(w, "file too large (max 10 MB)", http.StatusRequestEntityTooLarge)
288			return
289		}
290	
291		fileID := uuid.New().String()
292		mimeType := header.Header.Get("Content-Type")
293		if mimeType == "" {
294			mimeType = mime.TypeByExtension(filepath.Ext(header.Filename))
295		}
296		if mimeType == "" {
297			mimeType = "application/octet-stream"
298		}
299	
300		if _, err := s.SaveFile(fileID, header.Filename, data); err != nil {
301			http.Error(w, "storage error", http.StatusInternalServerError)
302			return
303		}
304		if err := ws.PublishFile(r.Context(), fileID, header.Filename, mimeType, data); err != nil {
305			http.Error(w, "publish error: "+err.Error(), http.StatusInternalServerError)
306			return
307		}
308	
309		w.Header().Set("Content-Type", "application/json")
310		json.NewEncoder(w).Encode(map[string]any{
