package transport

import (
	"context"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"time"

	pubsub "github.com/libp2p/go-libp2p-pubsub"
	"github.com/libp2p/go-libp2p/core/host"
	"github.com/libp2p/go-libp2p/core/peer"
	"github.com/safecast/groove-go/internal/store"
)

const (
	MsgTypeChat = "chat"
	MsgTypeFile = "file"
	MaxFileSize = 10 * 1024 * 1024 // 10 MB
)

// Message is the wire format for all workspace messages (chat and file).
type Message struct {
	From      string    `json:"from"`
	Workspace string    `json:"workspace"`
	Body      string    `json:"body"`
	Timestamp time.Time `json:"ts"`
	// File fields (only set when MsgType == "file")
	MsgType  string `json:"msg_type,omitempty"`
	FileID   string `json:"file_id,omitempty"`
	FileName string `json:"file_name,omitempty"`
	FileMime string `json:"file_mime,omitempty"`
	FileSize int64  `json:"file_size,omitempty"`
	FileData string `json:"file_data,omitempty"` // base64-encoded bytes
}

// Workspace represents a joined pubsub topic (a shared channel).
type Workspace struct {
	name  string
	self  peer.ID
	topic *pubsub.Topic
	sub   *pubsub.Subscription
	ps    *pubsub.PubSub
	store *store.Store
}

// NewGossipSub creates a GossipSub router with a 16 MB max message size.
func NewGossipSub(ctx context.Context, h host.Host) (*pubsub.PubSub, error) {
	ps, err := pubsub.NewGossipSub(ctx, h,
		pubsub.WithMaxMessageSize(16*1024*1024),
	)
	if err != nil {
		return nil, fmt.Errorf("gossipsub: %w", err)
	}
	fmt.Println("[transport] GossipSub router started")
	return ps, nil
}

// JoinWorkspace joins (or creates) a pubsub topic for the named workspace.
func JoinWorkspace(ps *pubsub.PubSub, self peer.ID, name string, s *store.Store) (*Workspace, error) {
	topic, err := ps.Join("workspace-" + name)
	if err != nil {
		return nil, fmt.Errorf("join topic: %w", err)
	}
	sub, err := topic.Subscribe()
	if err != nil {
		return nil, fmt.Errorf("subscribe: %w", err)
	}
	fmt.Printf("[transport] joined workspace: %s\n", name)
	return &Workspace{name: name, self: self, topic: topic, sub: sub, ps: ps, store: s}, nil
}

// Publish sends a chat message to the workspace topic and persists it locally.
func (w *Workspace) Publish(ctx context.Context, body string) error {
	msg := Message{
		MsgType:   MsgTypeChat,
		From:      w.self.String(),
		Workspace: w.name,
		Body:      body,
		Timestamp: time.Now().UTC(),
	}
	return w.publish(ctx, msg)
}

// PublishFile sends a file to the workspace topic (max 10 MB).
func (w *Workspace) PublishFile(ctx context.Context, fileID, fileName, mime string, data []byte) error {
	if len(data) > MaxFileSize {
		return fmt.Errorf("file too large (%d bytes, max %d)", len(data), MaxFileSize)
	}
	msg := Message{
		MsgType:   MsgTypeFile,
		From:      w.self.String(),
		Workspace: w.name,
		Body:      fmt.Sprintf("📎 %s (%s)", fileName, humanSize(int64(len(data)))),
		Timestamp: time.Now().UTC(),
		FileID:    fileID,
		FileName:  fileName,
		FileMime:  mime,
		FileSize:  int64(len(data)),
		FileData:  base64.StdEncoding.EncodeToString(data),
	}
	return w.publish(ctx, msg)
}

func (w *Workspace) publish(ctx context.Context, msg Message) error {
	data, err := json.Marshal(msg)
	if err != nil {
		return err
	}
	if err := w.topic.Publish(ctx, data); err != nil {
		return err
	}
	if w.store != nil {
		_ = w.store.Save(store.Message(msg))
	}
	return nil
}

// ReadLoop blocks and prints every incoming message.
func (w *Workspace) ReadLoop(ctx context.Context) {
	w.ReadLoopInto(ctx, func(msg Message) {
		fmt.Printf("[%s] %s: %s\n", msg.Workspace, shortID(msg.From), msg.Body)
	})
}

// ReadLoopInto blocks and calls fn for every incoming message from other peers.
func (w *Workspace) ReadLoopInto(ctx context.Context, fn func(Message)) {
	for {
		m, err := w.sub.Next(ctx)
		if err != nil {
			return
		}
		if m.ReceivedFrom == w.self {
			continue
		}
		var msg Message
		if err := json.Unmarshal(m.Data, &msg); err != nil {
			continue
		}
		if w.store != nil {
			// Save metadata only (strip binary payload before storing)
			meta := msg
			meta.FileData = ""
			_ = w.store.Save(store.Message(meta))
		}
		fn(msg)
	}
}

// ListPeers returns the peer IDs currently in this workspace topic.
func (w *Workspace) ListPeers() []peer.ID {
	return w.ps.ListPeers("workspace-" + w.name)
}

func shortID(id string) string {
	if len(id) > 12 {
		return id[:12]
	}
	return id
}

func humanSize(b int64) string {
	switch {
	case b >= 1024*1024:
		return fmt.Sprintf("%.1f MB", float64(b)/1024/1024)
	case b >= 1024:
		return fmt.Sprintf("%.1f KB", float64(b)/1024)
	default:
		return fmt.Sprintf("%d B", b)
	}
}

package workspace

import (
	"context"
	"fmt"
	"path/filepath"
	"sync"

	pubsub "github.com/libp2p/go-libp2p-pubsub"
	"github.com/libp2p/go-libp2p/core/peer"
	"github.com/safecast/groove-go/internal/presence"
	"github.com/safecast/groove-go/internal/store"
	"github.com/safecast/groove-go/internal/transport"
)

// entry holds an active workspace topic, its local store, and presence tracker.
type entry struct {
	ws      *transport.Workspace
	store   *store.Store
	tracker *presence.Tracker
}

// Manager owns multiple named workspace channels. It is safe for concurrent use.
type Manager struct {
	ps       *pubsub.PubSub
	self     peer.ID
	storeDir string

	mu     sync.RWMutex
	active map[string]*entry
}

// New creates a Manager. storeDir is the base directory for per-channel stores.
func New(ps *pubsub.PubSub, self peer.ID, storeDir string) *Manager {
	return &Manager{
		ps:       ps,
		self:     self,
		storeDir: storeDir,
		active:   make(map[string]*entry),
	}
}

// Join creates or returns an existing channel by name.
func (m *Manager) Join(ctx context.Context, name string) (*transport.Workspace, *store.Store, *presence.Tracker, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if e, ok := m.active[name]; ok {
		return e.ws, e.store, e.tracker, nil
	}

	s, err := store.Open(filepath.Join(m.storeDir, name))
	if err != nil {
		return nil, nil, nil, fmt.Errorf("open store for %q: %w", name, err)
	}

	ws, err := transport.JoinWorkspace(m.ps, m.self, name, s)
	if err != nil {
		_ = s.Close()
		return nil, nil, nil, fmt.Errorf("join topic %q: %w", name, err)
	}

	tracker, err := presence.New(ctx, m.ps, m.self, name)
	if err != nil {
		_ = s.Close()
		return nil, nil, nil, fmt.Errorf("presence for %q: %w", name, err)
	}

	m.active[name] = &entry{ws: ws, store: s, tracker: tracker}
	fmt.Printf("[workspace] joined channel: %s\n", name)
	return ws, s, tracker, nil
}

// List returns the names of all currently joined channels.
func (m *Manager) List() []string {
	m.mu.RLock()
	defer m.mu.RUnlock()
	names := make([]string, 0, len(m.active))
	for name := range m.active {
		names = append(names, name)
	}
	return names
}

// Get returns the workspace, store and tracker for a channel, or false if not joined.
func (m *Manager) Get(name string) (*transport.Workspace, *store.Store, *presence.Tracker, bool) {
	m.mu.RLock()
	defer m.mu.RUnlock()
	e, ok := m.active[name]
	if !ok {
		return nil, nil, nil, false
	}
	return e.ws, e.store, e.tracker, true
}

// CloseAll shuts down all active channel stores.
func (m *Manager) CloseAll() {
	m.mu.Lock()
	defer m.mu.Unlock()
	for name, e := range m.active {
		_ = e.store.Close()
		delete(m.active, name)
	}
}

package main

import (
	"context"
	"flag"
	"fmt"
	"os"
	"os/signal"
	"path/filepath"
	"strings"
	"syscall"

	"github.com/safecast/groove-go/internal/node"
	"github.com/safecast/groove-go/internal/transport"
	"github.com/safecast/groove-go/internal/web"
	"github.com/safecast/groove-go/internal/workspace"
)

// multiFlag lets a flag be specified multiple times: --relay addr1 --relay addr2
type multiFlag []string

func (m *multiFlag) String() string  { return strings.Join(*m, ", ") }
func (m *multiFlag) Set(v string) error { *m = append(*m, v); return nil }

func main() {
	port      := flag.Int("port", 0, "libp2p TCP listen port (0 = random)")
	httpAddr  := flag.String("http", ":8080", "Web UI listen address")
	defaultCh := flag.String("workspace", "general", "Default channel to join on startup")
	dataDir   := flag.String("data", defaultDataDir(), "Base directory for local stores")
	enableDHT := flag.Bool("dht", true, "Enable Kademlia DHT for WAN peer discovery")

	var relayAddrs  multiFlag
	var bootstrapAddrs multiFlag
	flag.Var(&relayAddrs, "relay",
		"Static relay address (repeat for multiple):\n"+
			"  e.g. /ip4/1.2.3.4/tcp/4001/p2p/<peerID>")
	flag.Var(&bootstrapAddrs, "bootstrap",
		"DHT bootstrap peer (repeat for multiple; defaults to IPFS bootstrap nodes)")
	flag.Parse()

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Boot libp2p node with NAT traversal
	n, err := node.New(ctx, node.Config{
		ListenPort:   *port,
		StaticRelays: []string(relayAddrs),
	})
	if err != nil {
		fatal(err)
	}
	defer n.Close()

	// mDNS for LAN discovery
	mdnsSvc, err := node.StartMDNS(ctx, n.Host)
	if err != nil {
		fatal(err)
	}
	defer mdnsSvc.Close()

	// Kademlia DHT for WAN discovery
	if *enableDHT {
		if _, err := node.StartDHT(ctx, n.Host, []string(bootstrapAddrs)); err != nil {
			fmt.Fprintf(os.Stderr, "[dht] warning: %s\n", err)
			// non-fatal — LAN still works via mDNS
		}
	}

	ps, err := transport.NewGossipSub(ctx, n.Host)
	if err != nil {
		fatal(err)
	}

	mgr := workspace.New(ps, n.ID, *dataDir)
	defer mgr.CloseAll()

	if _, _, _, err := mgr.Join(ctx, *defaultCh); err != nil {
		fatal(err)
	}

	webSrv := web.New(n.ID.String(), mgr)
	go func() {
		if err := webSrv.ListenAndServe(ctx, *httpAddr); err != nil {
			fmt.Fprintf(os.Stderr, "[web] %s\n", err)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit
	fmt.Println("[groove-web] shutting down")
}

func defaultDataDir() string {
	home, err := os.UserHomeDir()
	if err != nil {
		return ".groove-data"
	}
	return filepath.Join(home, ".groove")
}

func fatal(err error) {
	fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
	os.Exit(1)
}

